using System;
using System.Collections.Generic;
using System.ComponentModel;
using System.Linq;
using System.Text;
using System.Threading.Tasks;

public class Configuration
{
    [Category("통신 설정")]
    [DisplayName("PLC 통신 포트")]
    [Description("사용할 통신 포트 (COM1~COM10) - 대상 LS PLC (115200)")]
    [TypeConverter(typeof(ComPortComboConverter1))]
    public string PlcPort { get; set; }

    [Category("통신 설정")]
    [DisplayName("LVDT 포트")]
    [Description("사용할 통신 포트 (COM1~COM10) - 대상 LVDT (57600)")]
    [TypeConverter(typeof(ComPortComboConverter1))]
    public string LvdtPort { get; set; }

    [Category("통신 설정")]
    [DisplayName("LOAD CELL 포트")]
    [Description("사용할 통신 포트 (COM1~COM10) - 대상 LOADCELL (115200)")]
    [TypeConverter(typeof(ComPortComboConverter1))]
    public string LoadCellPort { get; set; }


    [Category("기타 설정")]
    [DisplayName("비밀 번호")]
    [Description("관리자 비밀번호 - 0 이면 비밀번호 사용안함 모드")]
    public string strPassWord { get; set; }

    [Category("서보1 위치 설정")]
    [DisplayName("위치 1")]
    [Description("최초/대기 위치")]
    public int Servo1Pos1 { get; set; }

    [Category("서보1 위치 설정")]
    [DisplayName("위치 2")]
    [Description("검사 위치")]
    public int Servo1Pos2 { get; set; }

    [Category("서보1 위치 설정")]
    [DisplayName("위치 3")]
    [Description("검사 전 이동 위치")]
    public int Servo1Pos3 { get; set; }

    [Category("서보1 위치 설정")]
    [DisplayName("위치 4")]
    [Description("-")]
    public int Servo1Pos4 { get; set; }

    [Category("서보1 위치 설정")]
    [DisplayName("위치 5")]
    [Description("-")]    
    public int Servo1Pos5 { get; set; }

    [Category("서보1 속도 설정")]
    [DisplayName("속도 1")]
    [Description("위치1 진행시 속도")]
    public int Servo1Pos1Spd { get; set; }

    [Category("서보1 속도 설정")]
    [DisplayName("속도 2")]
    [Description("위치2 진행시 속도")]
    public int Servo1Pos2Spd { get; set; }

    [Category("서보1 속도 설정")]
    [DisplayName("속도 3")]    
    public int Servo1Pos3Spd { get; set; }

    [Category("서보1 속도 설정")]
    [DisplayName("속도 4")]
    public int Servo1Pos4Spd { get; set; }

    [Category("서보1 속도 설정")]
    [DisplayName("속도 5")]
    public int Servo1Pos5Spd { get; set; }

    [Category("서보2 위치 설정")]
    [DisplayName("위치 1")]
    public int Servo2Pos1 { get; set; }

    [Category("서보2 위치 설정")]
    [DisplayName("위치 2")]
    public int Servo2Pos2 { get; set; }

    [Category("서보2 위치 설정")]
    [DisplayName("위치 3")]
    public int Servo2Pos3 { get; set; }

    [Category("서보2 속도 설정")]
    [DisplayName("속도 1")]
    public int Servo2Pos1Spd { get; set; }

    [Category("서보2 속도 설정")]
    [DisplayName("속도 2")]
    public int Servo2Pos2Spd { get; set; }

    [Category("서보2 속도 설정")]
    [DisplayName("속도 3")]
    public int Servo2Pos3Spd { get; set; }

    [Category("서보1 조그 설정")]
    [DisplayName("조그 속도")]
    public int Servo1JogSpd { get; set; }

    [Category("서보2 조그 설정")]
    [DisplayName("조그 속도")]
    public int Servo2JogSpd { get; set; }

    [Category("검사 설정")]
    [DisplayName("하중 리미트(Kg)")]
    public double LoadLimit { get; set; } = 0;

    [Category("검사 설정")]
    [DisplayName("마스터 대비 이동 거리(mm)")]
    public double LoadLengthLimit { get; set; } = 0;

    [Category("검사 설정")]
    [DisplayName("하중 검사 스펙MIN(Kg)")]
    public double SpecLoadSpecMin { get; set; } = 0;

    [Category("검사 설정")]
    [DisplayName("하중 검사 스펙MAX(Kg)")]
    public double SpecLoadSpecMax { get; set; } = 0;

    [Category("검사 설정")]
    [DisplayName("볼트 삽입 길이 스펙 MIN(mm)")]
    public double BoltLenSpecMin { get; set; } = 0;

    [Category("검사 설정")]
    [DisplayName("볼트 삽입 길이 스펫 MAX(mm)")]
    public double BoltLenSpecMax { get; set; } = 0;

    [Category("볼트 토크")]
    [DisplayName("Min")]
    public double rndmin { get; set; } = 0;

    [Category("볼트 토크")]
    [DisplayName("MAX")]
    public double rndmax { get; set; } = 0;

    [Category("OffSet")]
    [DisplayName("LVDT_L")]
    public double lvdtoffset1 { get; set; } = 0;

    [Category("OffSet")]
    [DisplayName("LVDT_R")]
