    [Category("합격 치수 설정")]
    [DisplayName("압입 깊이 (mm)")]
    [Description("합격 판정 기준 압입 깊이")]
    public double PassDistance { get; set; } = 13;

    [Category("합격 치수 설정")]
    [DisplayName("공차 (±mm)")]
    [Description("압입 깊이 허용 공차")]
    public double PassDistanceTol { get; set; } = 0.2;

    public Configuration()
    {
        PlcPort = GlobalValues.PlcPort;
        LvdtPort = GlobalValues.LvdtPort;
        LoadCellPort = GlobalValues.LoadCellPort;

        strPassWord = GlobalValues.strPassWord;

        Servo1Pos1 = GlobalValues.Servo1Pos1;
        Servo1Pos2 = GlobalValues.Servo1Pos2;
        Servo1Pos3 = GlobalValues.Servo1Pos3;
        Servo1Pos4 = GlobalValues.Servo1Pos4;
        Servo1Pos5 = GlobalValues.Servo1Pos5;

        Servo1Pos1Spd = GlobalValues.Servo1Pos1Spd;
        Servo1Pos2Spd = GlobalValues.Servo1Pos2Spd;
        Servo1Pos3Spd = GlobalValues.Servo1Pos3Spd;
        Servo1Pos4Spd = GlobalValues.Servo1Pos4Spd;
        Servo1Pos5Spd = GlobalValues.Servo1Pos5Spd;

        Servo2Pos1 = GlobalValues.Servo2Pos1;
        Servo2Pos2 = GlobalValues.Servo2Pos2;
        Servo2Pos3 = GlobalValues.Servo2Pos3;

        Servo2Pos1Spd = GlobalValues.Servo2Pos1Spd;
        Servo2Pos2Spd = GlobalValues.Servo2Pos2Spd;
        Servo2Pos3Spd = GlobalValues.Servo2Pos3Spd;

        Servo1JogSpd = GlobalValues.Servo1JogSpd;
        Servo2JogSpd = GlobalValues.Servo2JogSpd;

        LoadLimit = GlobalValues.LoadLimit;
        LoadLengthLimit = GlobalValues.LoadLengthLimit;
        SpecLoadSpecMin = GlobalValues.SpecLoadSpecMin;
        SpecLoadSpecMax = GlobalValues.SpecLoadSpecMax;

        BoltLenSpecMin = GlobalValues.BoltLenSpecMin;
        BoltLenSpecMax = GlobalValues.BoltLenSpecMax;

        rndmin = GlobalValues.RndMin;
        rndmax = GlobalValues.RndMax;

        lvdtoffset1 = GlobalValues.LvdtOffset1;
        lvdtoffset2 = GlobalValues.LvdtOffset2;

        PassDistance = GlobalValues.PassDistance;
        PassDistanceTol = GlobalValues.PassDistanceTol;
    }

    public void Apply()
    {
        GlobalValues.PlcPort = PlcPort;
        GlobalValues.LvdtPort = LvdtPort;
        GlobalValues.LoadCellPort = LoadCellPort;
        GlobalValues.strPassWord = strPassWord;

        GlobalValues.Servo1Pos1 = Servo1Pos1;
        GlobalValues.Servo1Pos2 = Servo1Pos2;
        GlobalValues.Servo1Pos3 = Servo1Pos3;
        GlobalValues.Servo1Pos4 = Servo1Pos4;
        GlobalValues.Servo1Pos5 = Servo1Pos5;

        GlobalValues.Servo1Pos1Spd = Servo1Pos1Spd;
        GlobalValues.Servo1Pos2Spd = Servo1Pos2Spd;
        GlobalValues.Servo1Pos3Spd = Servo1Pos3Spd;
        GlobalValues.Servo1Pos4Spd = Servo1Pos4Spd;
        GlobalValues.Servo1Pos5Spd = Servo1Pos5Spd;

        GlobalValues.Servo2Pos1 = Servo2Pos1;
        GlobalValues.Servo2Pos2 = Servo2Pos2;
        GlobalValues.Servo2Pos3 = Servo2Pos3;

        GlobalValues.Servo2Pos1Spd = Servo2Pos1Spd;
        GlobalValues.Servo2Pos2Spd = Servo2Pos2Spd;
        GlobalValues.Servo2Pos3Spd = Servo2Pos3Spd;

        GlobalValues.Servo1JogSpd = Servo1JogSpd;
        GlobalValues.Servo2JogSpd = Servo2JogSpd;

        GlobalValues.LoadLimit = LoadLimit;
        GlobalValues.LoadLengthLimit = LoadLengthLimit;
        GlobalValues.SpecLoadSpecMin = SpecLoadSpecMin;
        GlobalValues.SpecLoadSpecMax = SpecLoadSpecMax;
        GlobalValues.BoltLenSpecMin = BoltLenSpecMin;
        GlobalValues.BoltLenSpecMax = BoltLenSpecMax;

        GlobalValues.RndMin = rndmin;
        GlobalValues.RndMax = rndmax;

        GlobalValues.LvdtOffset1 = lvdtoffset1;
        GlobalValues.LvdtOffset2 = lvdtoffset2;

        GlobalValues.PassDistance = PassDistance;
        GlobalValues.PassDistanceTol = PassDistanceTol;
    }

    private class ComPortComboConverter1 : StringConverter
    {
        public override bool GetStandardValuesSupported(ITypeDescriptorContext context) => true;
        public override bool GetStandardValuesExclusive(ITypeDescriptorContext context) => true;
        public override StandardValuesCollection GetStandardValues(ITypeDescriptorContext context)
        {
            var comPorts = Enumerable.Range(1, 10).Select(i => $"COM{i}").ToArray();
            return new StandardValuesCollection(comPorts);
