        }

        if (double.TryParse(valueStr, out double result))
        {
            return result;
        }

        // 숫자 변환 실패 시도 → 0으로 저장
        //Console.WriteLine($"[INI 경고] {section}:{key} = '{valueStr}' → 숫자 변환 실패, 기본값 0 저장");
        ini.WriteValue(section, key, "0");
        return 0.0;
    }
    public static int TryGetInt(IniFile ini, string section, string key, int defaultValue = 0)
    {
        string valueStr = ini.ReadValue(section, key);

        if (string.IsNullOrWhiteSpace(valueStr))
        {
            // 값이 없으면 기본값 저장
            ini.WriteValue(section, key, defaultValue.ToString());
            return defaultValue;
        }

        if (int.TryParse(valueStr, out int result))
        {
            return result;
        }

        // 숫자 변환 실패 → 기본값으로 저장
        ini.WriteValue(section, key, defaultValue.ToString());
        return defaultValue;
    }

    public static void LoadSettingsFromIni()
    {
        IniFile ini = new IniFile("config.ini");

        string savedstrPassWord = ini.ReadValue("System", "PassWord");
        strPassWord = string.IsNullOrWhiteSpace(savedstrPassWord) ? "0" : savedstrPassWord;

        string savedPort = ini.ReadValue("System", "PlcPort");
        PlcPort = string.IsNullOrWhiteSpace(savedPort) ? "COM1" : savedPort;

        string savedLvdtPort = ini.ReadValue("System", "LvdtPort");
