private void PlaySound(string fileName)
{
    try
    {
        string soundPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "SOUND", fileName);
        if (File.Exists(soundPath))
        {
            using (SoundPlayer player = new SoundPlayer(soundPath))
            {
                player.Play(); // 또는 player.PlaySync(); → 동기 실행
            }
        }
        else
        {
            Logger.Log($"파일이 존재하지 않습니다: {soundPath}");
        }
    }
    catch (Exception ex)
    {
        Logger.Log($"오디오 재생 오류: {ex.Message}");
    }

}
