        private string tmpLot = "";
        private string tmpDec = "";
        private bool CheckAndBackupIvImages()
        {
            string sourceFolder = @"C:\IV";

            if (!Directory.Exists(sourceFolder))
            {
                Logger.Log("[IV] 폴더가 존재하지 않습니다: " + sourceFolder);
                return false;
            }

            string[] files = Directory.GetFiles(sourceFolder)
                                      .Where(f => f.ToLower().EndsWith(".jpg") || f.ToLower().EndsWith(".jpeg"))
                                      .ToArray();

            if (files.Length == 0)
            {
                Logger.Log("[IV] 이미지 파일 없음");
                isIvProcessing = false;
                return false;
            }

            Logger.Log($"[IV] 총 {files.Length}개 파일 감지됨 → 백업 시작");

            foreach (string filePath in files)
            {
                string fileName = Path.GetFileName(filePath);
                string judgment = "";

                if (fileName.Contains("_OK_"))
                {
                    judgment = "OK";
                    lbMeasureDec.Text = "OK";
                    lbMeasureDec.ForeColor = System.Drawing.Color.Blue;
                    tmpDec = "OK";
                }
                else if (fileName.Contains("_NG_"))
                {
                    judgment = "NG";
                    lbMeasureDec.Text = "NG";
                    lbMeasureDec.ForeColor = System.Drawing.Color.Red;
                    tmpDec = "NG";
                }
                else
                {
                    Logger.Log($"[무시] 판정 문자열 없음: {fileName}");
                    continue;
                }

                Logger.Log($"[처리중] {fileName}");

                // 🔹 백업 대상 경로
                System.DateTime now = System.DateTime.Now;
                string timeStamp = now.ToString("HHmmss_fff");
                string exeFolder = Application.StartupPath;
                string backupFolder = Path.Combine(exeFolder, "ImageBackUp", now.ToString("yyyy"), now.ToString("MM"), now.ToString("dd"));
                string newFileName = $"{timeStamp}_{judgment}.jpg";
                string backupPath = Path.Combine(backupFolder, newFileName);

                tmpLot = newFileName;

                try
                {
                    Directory.CreateDirectory(backupFolder);
                    File.Copy(filePath, backupPath, true);
                    Logger.Log($"[백업 완료] {fileName} → {newFileName}");
                }
                catch (Exception ex)
                {
                    Logger.Log($"[오류] 백업 실패: {fileName} → {ex.Message}");
                    continue; // 복사 실패했으면 표시/삭제도 안 함
                }

                // 🔹 이전 이미지 해제
                if (pictureBox1.Image != null)
                {
                    pictureBox1.Image.Dispose();
                    pictureBox1.Image = null;
                    GC.Collect();
                    GC.WaitForPendingFinalizers();
                }

                // 🔹 복사된 백업 이미지를 표시
                try
                {
                    using (System.Drawing.Image img = System.Drawing.Image.FromFile(backupPath))
                    {
                        pictureBox1.Image = (System.Drawing.Image)img.Clone();
                    }
                }
                catch (Exception ex)
                {
                    Logger.Log($"[오류] 백업된 이미지 표시 실패: {newFileName} → {ex.Message}");
                }

                // 🔹 원본 삭제
                try
                {
                    File.Delete(filePath);
                    Logger.Log($"[삭제 완료] 원본 {fileName}");
                }
                catch (Exception ex)
                {
                    Logger.Log($"[삭제 실패] 원본 {fileName} → {ex.Message}");
                }
            }

            return true;
        }
